function GameConfig:parseGameConfig()
    local config = FileUtil.getConfigFromYml("config")
    GameConfig.initPos = VectorUtil.newVector3(config.initPos[1].x, config.initPos[1].y, config.initPos[1].z)
    GameConfig.initTowers = config.towerId[1]
    GameConfig.CheckFormulaInterval = config.CheckFormulaInterval
    GameConfig.FormulaTowerToBuildInterval = config.FormulaTowerToBuildInterval
    GameConfig.DestroyMonsterDelayTime = config.DestroyMonsterDelayTime
    GameConfig.GameOverTime = tonumber(config.GameOverTime) or 60
    GameConfig.WaitTeamMateTime = tonumber(config.WaitTeamMateTime) or 45
    GameConfig.ExchangeRate = tonumber(config.exchangeRate) or 1
    GameConfig.GameGoldExchangeRate = tonumber(config.GameGoldExchangeRate) or 1
    GameConfig.AddSpeed = tonumber(config.AddSpeed) or 0
end